svg.script:
(() => {
  const countries = document.querySelectorAll(".country");
  function selectCountry(country) {
    countries.forEach(item => item.classList.remove("selected"));
    country.classList.add("selected");
    const detail = {
      name: country.dataset.name,
      iso: country.dataset.iso,
      continent: country.dataset.continent,
      population: Number(country.dataset.population || 0),
      gdpMd: Number(country.dataset.gdpMd || 0)
    };
    window.dispatchEvent(new CustomEvent("impera:country-selected", { detail }));
    if (window.parent && window.parent !== window) {
      window.parent.postMessage({ type:"IMPERA_COUNTRY_SELECTED", ...detail }, "*");
    }
  }
  countries.forEach(country => {
    country.addEventListener("click", () => selectCountry(country));
    country.addEventListener("keydown", event => {
      if (event.key === "Enter" || event.key === " ") {
        event.preventDefault();
        selectCountry(country);
      }
    });
  });
})();
